```typescript
export type IngredientState =
  | { status: "none" }
  | { status: "active"; id: string; name: string; grams: number }
  | { status: "discontinued"; id: string; reason: string };

export type IngredientCommand =
  | { type: "register"; id: string; name: string }
  | { type: "restock"; grams: number }
  | { type: "consume"; grams: number }
  | { type: "discontinue"; reason: string };

export type IngredientEvent =
  | { type: "IngredientRegistered"; id: string; name: string }
  | { type: "IngredientRestocked"; grams: number }
  | { type: "IngredientConsumed"; grams: number }
  | { type: "IngredientDiscontinued"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const ingredientDecider: Decider<IngredientCommand, IngredientEvent, IngredientState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "IngredientRegistered", id: command.id, name: command.name }];
      case "restock":
        if (state.status === "discontinued") throw new DomainError("DISCONTINUED");
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (command.grams <= 0) throw new DomainError("BAD_GRAMS");
        return [{ type: "IngredientRestocked", grams: command.grams }];
      case "consume":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (command.grams > state.grams) throw new DomainError("INSUFFICIENT");
        return [{ type: "IngredientConsumed", grams: command.grams }];
      case "discontinue":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "IngredientDiscontinued", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "IngredientRegistered":
        return { status: "active", id: event.id, name: event.name, grams: 0 };
      case "IngredientRestocked":
        if (state.status !== "active") return state;
        return { ...state, grams: state.grams + event.grams };
      case "IngredientConsumed":
        if (state.status !== "active") return state;
        return { ...state, grams: state.grams - event.grams };
      case "IngredientDiscontinued":
        if (state.status !== "active") return state;
        return { status: "discontinued", id: state.id, reason: event.reason };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};

