        return [{ type: "FoodInspectionReported", score: command.score, at: command.at }];
      case "close":
        if (state.status !== "reported") throw new DomainError("NOT_REPORTED");
        return [{ type: "FoodInspectionClosed", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
