    switch (event.type) {
      case "FoodInspectionScheduled":
        return { status: "scheduled", id: event.id, facility: event.facility };
      case "FoodInspectionConducted":
        if (state.status !== "scheduled") return state;
        return { status: "conducted", id: state.id, facility: state.facility, conductedAt: event.at };
      case "FoodInspectionReported":
        if (state.status !== "conducted") return state;
        return { status: "reported", id: state.id, facility: state.facility, score: event.score, reportedAt: event.at };
