```typescript
export type MealSwapEvent =
  | { type: "MealSwapRequested"; userId: string; swapId: string; at: string }
  | { type: "MealSwapConfirmed"; userId: string; swapId: string; at: string }
  | { type: "MealSwapRejected"; userId: string; swapId: string; reason: string }
  | { type: "MealSwapCancelled"; userId: string; swapId: string };

export interface MealSwapView {
  readonly userId: string;
  readonly totalSwaps: number;
  readonly confirmed: number;
  readonly rejected: number;
  readonly lastSwapAt: string | null;
}

export const emptyView: MealSwapView = {
  userId: "",
  totalSwaps: 0,
  confirmed: 0,
  rejected: 0,
  lastSwapAt: null,
};

export function project(view: MealSwapView, event: MealSwapEvent): MealSwapView {
  switch (event.type) {
    case "MealSwapRequested":
      return {
        ...view,
        userId: view.userId === "" ? event.userId : view.userId,
        totalSwaps: view.totalSwaps + 1,
        lastSwapAt: event.at,
      };
    case "MealSwapConfirmed":
      return { ...view, confirmed: view.confirmed + 1, lastSwapAt: event.at };
    case "MealSwapRejected":
      return { ...view, rejected: view.rejected + 1 };
    case "MealSwapCancelled":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function buildView(events: readonly MealSwapEvent[]): MealSwapView {
  return events.reduce<MealSwapView>(project, emptyView);
}

