```typescript
export type RecipeTestEvent =
  | { type: "RecipeTestStarted"; testId: string; recipeId: string }
  | { type: "RecipeTestRated"; testId: string; recipeId: string; rating: number }
  | { type: "RecipeTestAborted"; testId: string };

export interface RecipeRatingRow {
  readonly recipeId: string;
  readonly ratings: number;
  readonly average: number;
}

export interface RecipeTestView {
  readonly rows: Readonly<Record<string, RecipeRatingRow>>;
}

export const emptyView: RecipeTestView = { rows: {} };

export function project(view: RecipeTestView, event: RecipeTestEvent): RecipeTestView {
  switch (event.type) {
    case "RecipeTestStarted":
      return view;
    case "RecipeTestRated": {
      const current = view.rows[event.recipeId] ?? { recipeId: event.recipeId, ratings: 0, average: 0 };
      const ratings = current.ratings + 1;
      const average = (current.average * current.ratings + event.rating) / ratings;
      const nextRow: RecipeRatingRow = { recipeId: event.recipeId, ratings, average };
      return { rows: { ...view.rows, [event.recipeId]: nextRow } };
    }
    case "RecipeTestAborted":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function leaderboard(view: RecipeTestView, limit: number): RecipeRatingRow[] {
  return Object.values(view.rows)
    .slice()
    .sort((a, b) => b.average - a.average)
    .slice(0, limit);
}

