```typescript
export type AllergenTagEvent =
  | { type: "AllergenTagged"; recipeId: string; allergen: string }
  | { type: "AllergenRemoved"; recipeId: string; allergen: string };

export interface AllergenIndexView {
  readonly byAllergen: Readonly<Record<string, ReadonlyArray<string>>>;
  readonly byRecipe: Readonly<Record<string, ReadonlyArray<string>>>;
}

export const emptyView: AllergenIndexView = { byAllergen: {}, byRecipe: {} };

function addTo(map: Readonly<Record<string, ReadonlyArray<string>>>, key: string, value: string): Readonly<Record<string, ReadonlyArray<string>>> {
  const current = map[key] ?? [];
  if (current.includes(value)) return map;
  return { ...map, [key]: [...current, value] };
}

function removeFrom(map: Readonly<Record<string, ReadonlyArray<string>>>, key: string, value: string): Readonly<Record<string, ReadonlyArray<string>>> {
  const current = map[key];
  if (!current) return map;
  const next = current.filter((v) => v !== value);
  return { ...map, [key]: next };
}

export function project(view: AllergenIndexView, event: AllergenTagEvent): AllergenIndexView {
  switch (event.type) {
    case "AllergenTagged":
      return {
        byAllergen: addTo(view.byAllergen, event.allergen, event.recipeId),
        byRecipe: addTo(view.byRecipe, event.recipeId, event.allergen),
      };
    case "AllergenRemoved":
      return {
        byAllergen: removeFrom(view.byAllergen, event.allergen, event.recipeId),
        byRecipe: removeFrom(view.byRecipe, event.recipeId, event.allergen),
      };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function recipesWithAllergen(view: AllergenIndexView, allergen: string): ReadonlyArray<string> {
  return view.byAllergen[allergen] ?? [];
}

