  readonly servings: number;
}

export type CurrentRecipe = RecipeV3;
export const CURRENT_VERSION = 3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(state: RecipeV1): RecipeV2 {
  return { ...state, cuisine: "unknown" };
}

function v2Tov3(state: RecipeV2): RecipeV3 {
  return { ...state, servings: 1 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentRecipe> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as RecipeV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as RecipeV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unsupported snapshot version ${snap.version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentRecipe };
}

export function loadSnapshot(snap: Snapshot<unknown>): CurrentRecipe {
  return upgradeSnapshot(snap).state;
}

```

Snapshots freeze derived state so replay is bounded; without a version tag an old snapshot loaded into new code is a silent type mismatch. The loader reads version, runs upgraders in order, and the assertion at the end pins the shape to the current schema.

