import { Effect } from "effect";

export type RecipeState =
  | { status: "none" }
  | { status: "draft"; id: string; title: string; steps: number }
  | { status: "published"; id: string };

export type RecipeCommand =
  | { type: "create"; id: string; title: string }
  | { type: "addStep" }
  | { type: "publish"; at: string };

export type RecipeEvent =
  | { type: "RecipeCreated"; id: string; title: string }
  | { type: "RecipeStepAdded" }
  | { type: "RecipePublished"; at: string };

export const initialRecipe: RecipeState = { status: "none" };

export function decide(c: RecipeCommand, s: RecipeState): RecipeEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "RecipeCreated", id: c.id, title: c.title }];
    case "addStep":
      if (s.status !== "draft") throw new Error("NOT_DRAFT");
      return [{ type: "RecipeStepAdded" }];
    case "publish":
      if (s.status !== "draft") throw new Error("NOT_DRAFT");
      if (s.steps === 0) throw new Error("NO_STEPS");
      return [{ type: "RecipePublished", at: c.at }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: RecipeState, e: RecipeEvent): RecipeState {
  switch (e.type) {
    case "RecipeCreated":
      return { status: "draft", id: e.id, title: e.title, steps: 0 };
    case "RecipeStepAdded":
      if (s.status !== "draft") return s;
      return { ...s, steps: s.steps + 1 };
    case "RecipePublished":
      if (s.status !== "draft") return s;
      return { status: "published", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: RecipeEvent }>>;
  appendToStream(stream: string, events: readonly RecipeEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export function handle(store: EventStore, stream: string, command: RecipeCommand) {
  return Effect.gen(function* () {
    const stored = yield* Effect.promise(() => store.readStream(stream));
    const state = stored.reduce<RecipeState>((s, { event }) => evolve(s, event), initialRecipe);
    const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    const events = decide(command, state);
    yield* Effect.promise(() => store.appendToStream(stream, events, { expectedRevision: expected }));
  });
}

