```typescript
export type FoodInspectionEvent =
  | { type: "FoodInspectionScheduled"; id: string; facility: string }
  | { type: "FoodInspectionReported"; id: string; score: number };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventRecord<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface EventFeed<E> {
  subscribe(from: bigint): AsyncIterable<EventRecord<E>>;
}

export interface InspectionRow {
  readonly id: string;
  readonly facility: string;
  readonly score: number | null;
}

export interface ReadStore {
  upsert(row: InspectionRow): Promise<void>;
  get(id: string): Promise<InspectionRow | null>;
}

export function project(
  existing: InspectionRow | null,
  event: FoodInspectionEvent,
): InspectionRow | null {
  switch (event.type) {
    case "FoodInspectionScheduled":
      return { id: event.id, facility: event.facility, score: null };
    case "FoodInspectionReported":
      return existing ? { ...existing, score: event.score } : null;
    default: {
      const _n: never = event;
      return existing;
    }
  }
}

export async function runSubscription(
  name: string,
  feed: EventFeed<FoodInspectionEvent>,
  read: ReadStore,
  checkpoints: CheckpointStore,
): Promise<void> {
  const last = await checkpoints.read(name);
  const from: bigint = last ?? 0n;
  async function main(): Promise<void> {
    for await (const { position, event } of feed.subscribe(from)) {
      const existing = await read.get("id" in event ? event.id : "");
      const next = project(existing, event);
      if (next) await read.upsert(next);
      await checkpoints.write(name, position);
    }
  }
  await main();
}

```

Writing the checkpoint before the projection risks losing an event: if the projection throws, the checkpoint has already advanced and the runner will skip the failed event on restart. Persist side effects first, then commit the cursor — crash-safe replay depends on exactly that ordering.

