interface RecipeCreatedV1 {
  type: "RecipeCreated";
  version: 1;
  name: string;
  id: string;
}

interface RecipeStepAddedV1 {
  type: "RecipeStepAdded";
  version: 1;
}

interface RecipeCreatedV2 {
  type: "RecipeCreated";
  version: 2;
