export type MealSwapEvent =
  | { type: "MealSwapRequested"; userId: string; swapId: string }
  | { type: "MealSwapConfirmed"; userId: string; swapId: string; at: string };

export interface MealSwapView {
  readonly userId: string;
  readonly requested: number;
  readonly confirmed: number;
}

export function project(view: MealSwapView, event: MealSwapEvent): MealSwapView {
  switch (event.type) {
    case "MealSwapRequested":
      return { userId: event.userId, requested: view.requested + 1, confirmed: view.confirmed };
    case "MealSwapConfirmed":
      return { userId: event.userId, requested: view.requested, confirmed: view.confirmed + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface EventPage<E> {
  readonly events: ReadonlyArray<{ position: bigint; event: E }>;
  readonly nextCursor: bigint | null;
}

export interface EventStore<E> {
  readBatch(from: bigint, batchSize: number): Promise<EventPage<E>>;
}

export interface ReadStore<V> {
  write(userId: string, view: V): Promise<void>;
  read(userId: string): Promise<V | null>;
}

export interface RebuildOptions<E, V> {
  from: bigint;
  batchSize: number;
  store: EventStore<E>;
  read: ReadStore<V>;
  project: (view: V, event: E) => V;
  empty: (key: string) => V;
  keyOf: (event: E) => string;
  report?: (pos: bigint) => void;
}

export async function rebuild(options: RebuildOptions<MealSwapEvent, MealSwapView>): Promise<void> {
  let cursor: bigint | null = options.from;
  while (cursor !== null) {
    const page = await options.store.readBatch(cursor, options.batchSize);
    for (const { event } of page.events) {
      const key = options.keyOf(event);
      const current = (await options.read.read(key)) ?? options.empty(key);
      const next = options.project(current, event);
      await options.read.write(key, next);
    }
    if (page.events.length > 0) options.report?.(page.events[page.events.length - 1]!.position);
    cursor = page.nextCursor;
  }
}

