```typescript
export type RecipeCommand =
  | { type: "create"; id: string; title: string }
  | { type: "publish"; at: string };

export type RecipeEvent =
  | { type: "RecipeCreated"; id: string; title: string }
  | { type: "RecipePublished"; at: string };

export type RecipeWriteState =
  | { status: "none" }
  | { status: "draft"; id: string }
  | { status: "published"; id: string };

export const initialWrite: RecipeWriteState = { status: "none" };

export function decide(c: RecipeCommand, s: RecipeWriteState): RecipeEvent[] {
  if (c.type === "create") {
    if (s.status !== "none") throw new Error("EXISTS");
    return [{ type: "RecipeCreated", id: c.id, title: c.title }];
  }
  if (c.type === "publish") {
    if (s.status !== "draft") throw new Error("NOT_DRAFT");
    return [{ type: "RecipePublished", at: c.at }];
  }
  const _n: never = c;
  throw new Error("UNKNOWN");
}

export function evolve(s: RecipeWriteState, e: RecipeEvent): RecipeWriteState {
  switch (e.type) {
    case "RecipeCreated": return { status: "draft", id: e.id };
    case "RecipePublished": return s.status === "draft" ? { status: "published", id: s.id } : s;
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";
export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: RecipeEvent }>>;
  appendToStream(stream: string, events: readonly RecipeEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handleCommand(store: EventStore, id: string, command: RecipeCommand): Promise<void> {
  const stream = `recipe-${id}`;
  const stored = await store.readStream(stream);
  const state = stored.reduce<RecipeWriteState>((s, { event }) => evolve(s, event), initialWrite);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, decide(command, state), { expectedRevision: expected });
}

export interface RecipeReadRow {
  readonly id: string;
  readonly title: string;
  readonly publishedAt: string | null;
}

export interface ReadStore {
  get(id: string): Promise<RecipeReadRow | null>;
}

// The read store is eventually consistent with the event store; writers may have
// appended events that have not yet been projected into this view.
export async function queryView(read: ReadStore, id: string): Promise<RecipeReadRow | null> {
  return read.get(id);
}

```

Writes and reads are two different jobs. The write side is about protecting invariants — state is whatever decide needs to reject bad commands. The read side is about serving queries cheaply — state is denormalised fields your UI wants. Sharing one state type ties read performance to write invariants.

```typescript
export type DietPlanCommand =
  | { type: "draft"; id: string }
  | { type: "activate"; at: string };

export type DietPlanEvent =
  | { type: "DietPlanDrafted"; id: string }
  | { type: "DietPlanActivated"; at: string };

export type DietPlanWriteState =
  | { status: "none" }
  | { status: "drafted"; id: string }
  | { status: "active"; id: string };

export const initialWrite: DietPlanWriteState = { status: "none" };

export function decide(c: DietPlanCommand, s: DietPlanWriteState): DietPlanEvent[] {
  switch (c.type) {
    case "draft":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "DietPlanDrafted", id: c.id }];
    case "activate":
      if (s.status !== "drafted") throw new Error("NOT_DRAFTED");
      return [{ type: "DietPlanActivated", at: c.at }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export function evolve(s: DietPlanWriteState, e: DietPlanEvent): DietPlanWriteState {
  switch (e.type) {
    case "DietPlanDrafted": return { status: "drafted", id: e.id };
    case "DietPlanActivated": return s.status === "drafted" ? { status: "active", id: s.id } : s;
    default: { const _n: never = e; return s; }
  }
}

export type ExpectedRevision = bigint | "no_stream";
export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: DietPlanEvent }>>;
  appendToStream(stream: string, events: readonly DietPlanEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export async function handleCommand(store: EventStore, id: string, command: DietPlanCommand): Promise<void> {
  const stream = `dietplan-${id}`;
  const stored = await store.readStream(stream);
  const state = stored.reduce<DietPlanWriteState>((s, { event }) => evolve(s, event), initialWrite);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, decide(command, state), { expectedRevision: expected });
}

// The read model is denormalised for query paths and is eventually consistent
// with the event store; never import the write state type here.
export interface DietPlanSummaryRow {
  readonly id: string;
  readonly activatedAt: string | null;
}
export interface ReadStore { get(id: string): Promise<DietPlanSummaryRow | null>; }

export async function queryView(read: ReadStore, id: string): Promise<DietPlanSummaryRow | null> {
  return read.get(id);
}

