export type RecipeIntegrationEvent =
  | { schema: "recipe.published.v1"; payload: { id: string; publishedAt: string } }
  | { schema: "recipe.retired.v1"; payload: { id: string; retiredAt: string } };

export function translate(event: RecipeDomainEvent): RecipeIntegrationEvent | null {
  switch (event.type) {
    case "RecipeCreated":
      return null;
    case "RecipeStepAdded":
      return null;
    case "RecipePublished":
      return { schema: "recipe.published.v1", payload: { id: event.id, publishedAt: event.at } };
    case "RecipeRetired":
      return { schema: "recipe.retired.v1", payload: { id: event.id, retiredAt: event.at } };
    default: {
      const _n: never = event;
      return null;
    }
  }
}

export function translateBatch(events: ReadonlyArray<RecipeDomainEvent>): ReadonlyArray<RecipeIntegrationEvent> {
  const out: RecipeIntegrationEvent[] = [];
  for (const event of events) {
    const translated = translate(event);
    if (translated) out.push(translated);
  }
  return out;
}

export interface PublishStats {
  readonly published: number;
  readonly retired: number;
}

export const emptyStats: PublishStats = { published: 0, retired: 0 };

export function project(stats: PublishStats, event: RecipeDomainEvent): PublishStats {
  switch (event.type) {
    case "RecipeCreated":
    case "RecipeStepAdded":
      return stats;
    case "RecipePublished":
      return { ...stats, published: stats.published + 1 };
    case "RecipeRetired":
      return { ...stats, retired: stats.retired + 1 };
    default: {
      const _n: never = event;
      return stats;
    }
  }
}

