export type PantryStockEvent =
  | { type: "PantryStockOpened"; id: string }
  | { type: "PantryStocked"; grams: number }
  | { type: "PantryDrawn"; grams: number };

export interface PantryStockAggregate {
  readonly id: string;
  readonly grams: number;
  readonly opened: boolean;
}

export const emptyPantry: PantryStockAggregate = { id: "", grams: 0, opened: false };

export function when(state: PantryStockAggregate, event: PantryStockEvent): PantryStockAggregate {
  switch (event.type) {
    case "PantryStockOpened":
      return { id: event.id, grams: 0, opened: true };
    case "PantryStocked":
      return { ...state, grams: state.grams + event.grams };
    case "PantryDrawn":
      return { ...state, grams: state.grams - event.grams };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregate(events: ReadonlyArray<PantryStockEvent>): PantryStockAggregate {
  return events.reduce<PantryStockAggregate>(when, emptyPantry);
}

export function isPantryStock(value: Partial<PantryStockAggregate>): value is PantryStockAggregate {
  return typeof value.id === "string" && value.id.length > 0 && typeof value.grams === "number" && value.opened === true;
}

