import { Effect } from "effect";

export type MealSwapEvent =
  | { type: "MealSwapRequested"; swapId: string; userId: string }
  | { type: "MealSwapConfirmed"; swapId: string; userId: string; at: string };

export interface MealSwapRow {
  readonly userId: string;
  readonly requested: number;
  readonly confirmed: number;
}

export function project(row: MealSwapRow, event: MealSwapEvent): MealSwapRow {
  switch (event.type) {
    case "MealSwapRequested":
      return { userId: event.userId, requested: row.requested + 1, confirmed: row.confirmed };
    case "MealSwapConfirmed":
      return { userId: event.userId, requested: row.requested, confirmed: row.confirmed + 1 };
    default: {
      const _n: never = event;
      return row;
    }
  }
}

export interface ReadStore {
  read(userId: string): Promise<MealSwapRow | null>;
  write(userId: string, row: MealSwapRow): Promise<void>;
}

export interface EventFeed {
  next(): Promise<MealSwapEvent | null>;
}

export function runProjection(feed: EventFeed, read: ReadStore) {
  return Effect.gen(function* () {
    let event: MealSwapEvent | null = yield* Effect.promise(() => feed.next());
    while (event !== null) {
      const current: MealSwapRow = (yield* Effect.promise(() => read.read(event!.userId))) ?? { userId: event.userId, requested: 0, confirmed: 0 };
      const updated = project(current, event);
      yield* Effect.promise(() => read.write(event!.userId, updated));
      event = yield* Effect.promise(() => feed.next());
    }
  });
}

